using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace McpServer;

[McpServerToolType]
public sealed class ApiFetchTool
{
    [McpServerTool, Description("Fetches data from an external API endpoint.")]
    public static async Task<string> FetchData(
        IHttpClientFactory httpClientFactory,
        ILogger<ApiFetchTool> logger,
        [Description("The API path to call, e.g. /users/1")] string path)
    {
        var client = httpClientFactory.CreateClient("api");

        logger.LogInformation("Fetching {Path}", path);

        try
        {
            var response = await client.GetAsync(path);
            response.EnsureSuccessStatusCode();

            var json = await response.Content.ReadFromJsonAsync<JsonElement>();
            return JsonSerializer.Serialize(json, new JsonSerializerOptions { WriteIndented = true });
        }
        catch (HttpRequestException ex)
        {
            logger.LogError(ex, "API request to {Path} failed", path);
            return $"Error: {ex.StatusCode} — {ex.Message}";
        }
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt, Description("Generates a prompt that asks the model to summarize the given text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize")] string text,
        [Description("Target summary style: brief, detailed, or bullet-points")] string style = "brief")
    {
        return
        [
            new PromptMessage
            {
                Role = Role.User,
                Content = new Content
                {
                    Type = "text",
                    Text = $"Summarize the following text in a {style} style:\n\n{text}"
                }
            }
        ];
    }
}

